// ── Embedded logos (base64) — works from file:/// without CORS issues ──
const LOGO_MAIN  = 'data:image/png;base64,';
const LOGO_FORM  = 'data:image/png;base64,';
const LOGO_NAV   = 'data:image/png;base64,';

// Patch all document logo <img> elements to use embedded src
function patchDocumentLogos() {
  document.querySelectorAll('.document-logo img, .index-document .document-logo img').forEach(img => {
    img.src = LOGO_MAIN;
  });
  document.querySelectorAll('.form-logo img').forEach(img => {
    img.src = LOGO_FORM;
  });
  document.querySelectorAll('.nav-icon').forEach(img => {
    img.src = LOGO_NAV;
  });
}

document.addEventListener('DOMContentLoaded', patchDocumentLogos);

// ============================================================
//  DIU CSE Cover Page — script.js
//  Fix: document is always 780px in DOM.
//       Mobile preview uses CSS transform:scale().
//       Download temporarily removes the scale so html2canvas
//       always captures a consistent A4-sized element.
// ============================================================

// ── Helpers ──────────────────────────────────────────────────

function formatDate(dateString) {
  if (!dateString) return '';
  const d = new Date(dateString);
  if (isNaN(d.getTime())) return '';
  const day   = String(d.getDate()).padStart(2, '0');
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const year  = d.getFullYear();
  return `${day}-${month}-${year}`;
}

// ── Scale the cover-page preview to fit the viewport ─────────
function updateDocumentScale() {
  const wrapper = document.getElementById('doc-scale-wrapper');
  if (!wrapper) return;

  // doc-holder contains ONLY the scale wrapper now (buttons are a sibling outside)
  const holder    = document.getElementById('doc-holder');
  const available = holder
    ? holder.getBoundingClientRect().width
    : wrapper.parentElement.getBoundingClientRect().width;

  const docWidth  = 780;
  const docHeight = 1122.92;
  const scale     = Math.min(1, available / docWidth);

  wrapper.style.transform       = `scale(${scale})`;
  wrapper.style.transformOrigin = 'top center';

  // Shrink only the holder (buttons sit outside it as a sibling — not clipped)
  if (holder) holder.style.height = `${docHeight * scale}px`;
}

window.addEventListener('resize', updateDocumentScale);

// ── Right-click disabled ──────────────────────────────────────
document.addEventListener('contextmenu', e => e.preventDefault());

// ── Enter-key navigation ──────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  const inputs = Array.from(document.querySelectorAll('input'));
  inputs.forEach((input, i) => {
    input.addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        e.preventDefault();
        const next = inputs[i + 1];
        next ? next.focus() : document.querySelector('.submit')?.focus();
      }
    });
  });
});

