// ── Show document + scale ─────────────────────────────────────
function showDocument() {
  const form    = document.querySelector('.form');
  const docEl   = document.getElementById('document');
  const buttons = document.getElementById('doc-buttons');
  if (form)    form.style.display    = 'none';
  if (docEl)   docEl.style.display   = 'block';
  if (buttons) buttons.style.display = 'flex';
  updateDocumentScale();
  document.querySelector('.document-holder')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function showIndexDocument() {
  const form    = document.querySelector('.form');
  const docEl   = document.getElementById('index-document');
  const buttons = document.getElementById('doc-buttons');
  if (form)    form.style.display    = 'none';
  if (docEl)   docEl.style.display   = 'block';
  if (buttons) buttons.style.display = 'flex';
  updateDocumentScale();
  document.querySelector('.document-holder')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

// ── Download — temporarily remove scale then restore ──────────
async function captureAndDownload(format) {
  const target  = document.getElementById('document') || document.getElementById('index-document');
  const wrapper = document.getElementById('doc-scale-wrapper');
  if (!target || target.style.display === 'none') return;

  // Show loading overlay
  const overlay = document.getElementById('download-overlay');
  if (overlay) overlay.classList.add('active');

  // Snapshot current transform, then reset it so html2canvas
  // sees the element at its true 780px layout size
  const savedTransform = wrapper ? wrapper.style.transform : '';
  if (wrapper) {
    wrapper.style.transform       = 'none';
    wrapper.style.transformOrigin = 'top center';
  }

  // Small delay so the DOM repaints before capture
  await new Promise(r => setTimeout(r, 80));

  try {
    const canvas = await html2canvas(target, {
      scale:           4,          // high-res
      useCORS:         true,
      backgroundColor: '#ffffff',
      width:           780,
      height:          1122.92,
      logging:         false,
    });

    if (format === 'pdf') {
      const { jsPDF } = window.jspdf;
      const pdf = new jsPDF({
        orientation: 'portrait',
        unit:        'px',
        format:      [780, 1122.92],
        compress:    true,
      });
      pdf.addImage(canvas, 'JPEG', 0, 0, 780, 1122.92, '', 'FAST');
      pdf.save('diu-cover-page.pdf');
    } else {
      const link      = document.createElement('a');
      link.download   = 'diu-cover-page.jpeg';
      link.href       = canvas.toDataURL('image/jpeg', 1.0);
      link.click();
    }
  } catch (err) {
    console.error('Capture failed:', err);
    alert('Download failed. Please try again.');
  } finally {
    // Restore visual scale
    if (wrapper) {
      wrapper.style.transform       = savedTransform;
      wrapper.style.transformOrigin = 'top center';
    }
    if (overlay) overlay.classList.remove('active');
  }
}

// ── Wire up download buttons ──────────────────────────────────
document.getElementById('downloadPdf')?.addEventListener('click',   () => captureAndDownload('pdf'));
document.getElementById('downloadImage')?.addEventListener('click', () => captureAndDownload('image'));
